export const lessons: Lesson[] = [
  { slug: "obstacles-to-confidence", title: "Free Preview: Obstacles to Confidence", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/obstacles-to-confidence.png", duration: "17m 26s", access: "free", courseSlug: null, order: null, description: "Free Preview: Avoid These Confidence Killers At All Costs", details: "<h6><em>From our Premium Membership collection, enjoy this free preview! </em></h6><h5>Fed up with feeling held back? Stop making excuses and avoid the confidence killers that are hindering your progress!</h5><p>Discover how to break free from your self-sabotaging thoughts and rewrite your story to unleash your true potential. Once you do, you'll be able to:</p><ul><li>Go from being shackled by impostor syndrome to owning your worth</li><li>Go from comparing yourself to others to embracing your unique abilities</li><li>Go from being influenced by friends and family to living life on your own terms</li><li>Go from being affected by haters and toxic people to brushing off negativity</li><li>Go from past rejections to embracing new opportunities with confidence</li></ul><p>You'll have the tools to eliminate the layers of self-imposed limitations and build unshakable confidence, paving the way for you to pursue your dreams fearlessly.</p><p>We'll cover:</p><p>1. Identifying Your Bullshit Story: Learn to recognize the stories and excuses you tell yourself that are inhibiting your confidence and holding you back from reaching your full potential.</p><p>2. Overcoming Impostor Syndrome: Understand that feeling like a fraud is a common experience and uncover strategies to combat this crippling mindset.</p><p>3. Resisting External Obstacles: Explore the impact of societal norms, friends and family, haters, and past experiences on your confidence, and discover how to navigate and rise above these challenges.</p>", streamId: "816edc4a8dd448f7cdcfa8c3aa150a07", backdrop: "/backdrops/obstacles-to-confidence.jpg" },
  { slug: "epic-goals", title: "Free Preview: Goal Setting That Works", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/epic-goals.png", duration: "17m 50s", access: "free", courseSlug: null, order: null, description: "Free Preview of the Goals Workshop: Forget SMART Goals, This Method Actually Works", details: "<h6><em>From our Premium Membership collection, enjoy this free preview! </em></h6><h5>How to go from pursuing things that don't matter to setting and achieving goals that truly fulfill you.</h5><p>Struggling with achieving your goals? Fed up with wasting time pursuing things that don't matter? Here's a new way to set goals that actually works.</p><p>Most goals are not aligned with your mission. Without a clear mission guiding us, you risk wasting time pursuing things that don't align with your purpose. Setting goals haphazardly leaves you unfocused, diluting your efforts and hindering your success.</p><p>You will learn a method of setting goals that are aligned with your mission, ensuring you achieve what truly matters to you and avoid wasting time on pursuits that don't resonate with your purpose.</p><p>You will gain clarity on how to set goals that are congruent with your life mission, leading to a higher chance of success and fulfillment in your pursuits.</p><p>1. Discover the importance of aligning your goals with your overarching mission and how it can make a significant difference in the outcomes you achieve.</p><p>2. Learn to segment your goals into short, medium, and long-term categories, and prioritize them based on your elevated personal instruction code, ensuring a focused approach to achieving your objectives.</p><p>3. Uncover the powerful technique of ruthlessly eliminating extraneous goals and laser-focusing on your top 3 keystone goals, enhancing your effectiveness and productivity in goal achievement.</p>", streamId: "f65fcb2436fbcf2444205fc14447f84e", backdrop: "/backdrops/epic-goals.jpg" },
  { slug: "human-interaction-skills", title: "Mastering Human Interaction Skills Introduction", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/human-interaction-skills.png", duration: "3m 45s", access: "free", courseSlug: null, order: null, description: "Introduction To Mastering Human Interaction Skills for Success and Influence", details: "<h5>Quit making lousy first impressions and learn to exude confidence effortlessly.</h5><p>You'll discover why giving off a lousy first impression is costing you opportunities and how to master human interaction skills to gain respect and attractiveness effortlessly.</p><p>Implementing the strategies from this lesson will help you not only to exude confidence effortlessly but also to earn respect and become more attractive in various social and professional settings.</p><p>- Uncover the crucial elements of human interaction and learn to read other people's body language effectively.</p><p>- Master the art of controlling your body language to exude confidence and control the visual communication that gives off the right impression.</p><p>- Develop skills in posture, stance, eye contact, conversation starting and maintenance, storytelling, handshakes, and tonality to enhance your social and professional interactions.</p><p>Learn to master human interaction skills, from reading body language to controlling your own. It's not just about what you say, but also how you present yourself. Boost your confidence, make a killer first impression, and level up your professional and social interactions. Elevate your posture, handshake, voice, and more. Own the environment and take charge of your interactions. Dominate your first impressions and conquer every room. </p><p>This lesson will guide you through the importance of human interaction skills in making a strong first impression and how it impacts our professional and social interactions. You'll learn about body language, posture, social etiquette, and communication skills. </p>", streamId: "de9bfda0f57f661785d3ad7a8e64397d", backdrop: "/backdrops/human-interaction-skills.jpg" },
  { slug: "double-your-job-offers-intro", title: "Double Your Job Offers Intro", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/double-your-job-offers-intro.png", duration: "11m 38s", access: "free", courseSlug: null, order: null, description: "How To Stand Out Among Other Candidates And Recruiters, Giving You The Competitive Edge You Need To Land Your Dream Job", details: "<p>Are you feeling stuck in a job you don't like and dreaming of transitioning to a new career or starting a business? In the \"Double Your Job Offers\" Masterclass series, Lee shares insights and strategies to help you confidently make that transition, even if you lack experience. You'll discover the keys to standing out among other candidates and making a successful career change. </p><p>This isn't your typical job hunting advice. We won't just talk about resumes and cover letters. In this training, you'll learn how to stand out among other candidates and recruiters, giving you the competitive edge you need to land your dream job.</p>", streamId: "91592421667eae43635f7bf729861267", backdrop: "/backdrops/double-your-job-offers-intro.jpg" },
  { slug: "grab-control", title: "Genuine, Refined, Attractive Behavior Introduction", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/grab-control.png", duration: "12m 24s", access: "free", courseSlug: null, order: null, description: "GRAB Control Intro: How To Become More Attractive While Still Being Yourself", details: "<h5>Why do men struggle to become more attractive while staying true to themselves?</h5><p>In this lesson, we will equip you with the tools to master genuine, refined, attractive behavior. &nbsp;You'll be able to command respect and attention from everyone you interact with, whether it's in your personal or professional life.</p><p>You'll discover:</p><p>- How to go from struggling with self-esteem to exuding natural, inner confidence</p><p>- From lacking confidence to becoming magnetic and charming</p><p>- Going from easily manipulated to commanding respect </p><p>Develop a true, genuine inner confidence that aligns with your authentic self and amplifies your attractiveness to others, leading to increased respect, attention, and success in all areas of your life.</p><p>We cover:</p><p>1. Understanding the essence of genuine, refined, attractive behavior and how it forms the foundation of inner confidence and magnetism.</p><p>2. Identifying areas where you are already exhibiting genuine and authentic behavior versus where you might be lacking, and learning how to shift and internalize confident behaviors.</p><p>3. Being perceived as attractive, and avoiding being easily manipulated or triggered in various interpersonal and professional scenarios.</p>", streamId: "c5b92eac86f8dd77ad1a6bf5e4922921", backdrop: "/backdrops/grab-control.jpg" },
  { slug: "chris-haddad-interview", title: "Special Guest Interview: Chris Haddad", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/chris-haddad-interview.png", duration: "1h 5m", access: "free", courseSlug: null, order: null, description: "Masculinity, Money, Relationships, and More with $750 Million Copywriter Chris Haddad", details: "<h5>The golden thread linking masculinity, dating, and marketing.</h5><p>In this special interview, copywriter extraordinaire Chris Haddad and Lee Lambert cover topics ranging from masculinity to business. They share their experiences with narcissism in relationships, the fear of failure, and building a reputation online.</p><p>They cover the concepts of toxic masculinity and toxic femininity, emphasizing the importance of being a more attractive and respectful individual. Additionally, they highlight the connection between masculinity, dating principles, and marketing strategies.</p><p>They also discuss selling without sales calls and the challenges of affiliate launches. Chris shares his approach to creating offers and the structure of his story beats. He emphasizes the importance of understanding the market and creating an offer that resonates with the audience. Chris Haddad discusses the power of effective copywriting and the impact it can have on marketing. &nbsp;</p>", streamId: "6d9d5afc8ff18372bf98be5332000a45", backdrop: "/backdrops/chris-haddad-interview.jpg" },
  { slug: "free-preview-masculinity-unlocked-intro", title: "Free Preview: Midlife Masculinity Unlocked - Reclaim Your Masculinity", category: "Masculinity", categorySlug: "masculinity", instructorSlugs: ["dan-lavoie"], thumbnail: "/thumbnails/free-preview-masculinity-unlocked-intro.png", duration: "21m 19s", access: "free", courseSlug: null, order: null, description: "Free Preview: The First Step To Being Your Own Man Again After Divorce", details: "<h6><em>From our Premium Membership collection, enjoy this free preview! </em></h6><h5>Why do men over 40 struggle to feel like they're good enough after divorce?</h5><p>In this introductory lesson from the Midlife Masculinity Unlocked series, you'll discover how you can:</p><ul><li>Go From Struggling with Self-Worth to Discovering Your Inner Potential and Confidence</li><li>Go From Being Unable to Enforce Healthy Boundaries to Commanding Respect and Trust</li><li>Go From Failing to Recover from Setbacks to Building Unshakable Mental Resilience</li><li>Go From Struggling with People-Pleasing to Asserting Your Needs and Living Authentically</li></ul><p>Embrace a life where past struggles are stepping stones to a powerful self-image, motivating relationships, and an adventurous day-to-day existence that you control.</p><p>We cover:</p><ol><li><strong>Unlocking Self-Respect</strong>: Dive into Dan Lavoie's critical steps for personal growth that shift your mindset away from trying to please everyone else. Explore the simple tools to reclaim your place in your own life and cultivate a resilient, unshakeable sense of self.</li><li><strong>Strategic Recovery</strong>: Dan's approach focuses on mental strength and resilience techniques to foster rapid return to success, enabling you to live life on your own terms, unswayed by the fleeting opinions of others.</li><li><strong>Living the Adventure</strong>: Get inspired by the coaching strategies Dan provides to inject excitement back into your life. Rediscover hobbies, plan for balanced family adventures, and assess job satisfaction, elevating your lifestyle from mere survival to thriving in a life you absolutely love.</li></ol>", streamId: "c7423f07a9a9c99a4f6d29c2e62ac3a7", backdrop: "/backdrops/free-preview-masculinity-unlocked-intro.jpg" },
  { slug: "free-preview-midlife-strength-unlocked-intro", title: "Free Preview: Midlife Strength Unlocked - Transform Your Dad Bod", category: "Fitness & Nutrition", categorySlug: "fitness-nutrition", instructorSlugs: ["aidan-lee"], thumbnail: "/thumbnails/free-preview-midlife-strength-unlocked-intro.png", duration: "11m 36s", access: "free", courseSlug: null, order: null, description: "Free Preview: The Counter-Intuitive Way To Transform Your Dad Bod For Guys Over 40", details: "<h6><em>From our Premium Membership collection, enjoy this free preview! </em></h6><h5>How to go from a big-belly dad bod to a sleek, muscular \"Daddy\" bod, specifically for guys over 40</h5><p>In this free preview of the Midlife Strength Unlocked series, join functional strength and martial arts expert Aidan Lee as he shows men over 40 how to go from struggling with good health to achieving a Warrior's physique and work-life balance.</p><p>The first rule is, if you're over 40, you can't train like you did in your twenties. So if you're doing CrossFit, yoga, bodybuilding routines, or even boot camps, before your next session, STOP&nbsp;RIGHT&nbsp;NOW!</p><p>You'll discover a revolutionary approach that transcends traditional weight loss and muscle-building methods and taps into the holistic connection between posture, mind, and muscle. </p><p>It's not just an upgrade for your looks, but also an all-outwellness transformation.</p><p>Embrace the journey toward a warrior's physique and zen-like work-life balance, mastering functional movements that align with your body's natural mechanics, fostering resilience against age-related decline, and unlocking an invigorated sense of self that permeates through every facet of your life.</p><p>We cover:</p><ol><li><strong>Holistic Posture Alignment:</strong> Dive deep into Aidan Lee's insights on why your posture is the silent linchpin to long-term health and how addressing your alignment is about more than just looking good – it's about feeling strong, mobile, and youthful as you age.</li><li><strong>Functional Strength Training:</strong> Discover the power of integrating strength training with mindful movement, focusing on compound, multi-joint exercises that mimic real-life activities. Aidan Lee will debunk the myths of isolated single-muscle workouts and show you how to engage in a smarter, full-body approach that conditions your body to move as one efficient, powerful unit.</li><li><strong>Mental Grit and Philosophy in Fitness:</strong> Learn how the ancient wisdom from texts such as \"The Art of War\" and \"The Book of Five Rings\" can elevate your training and life strategies, as Aidan Lee explains the profound impact of incorporating a warrior’s mindset into your daily routine, especially when tackling the challenges of health, divorce, and mid-life transformation.</li></ol>", streamId: "b9459f91507c0226d97f9221e5ec7383", backdrop: "/backdrops/free-preview-midlife-strength-unlocked-intro.jpg" },
  { slug: "free-preview-instant-impressive-image-intro", title: "Free Preview: Instant Impressive Image Intro", category: "Image & Style", categorySlug: "image-style", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/free-preview-instant-impressive-image-intro.png", duration: "11m 12s", access: "free", courseSlug: null, order: null, description: "How To Go From Struggling To Dress Well To Effortlessly Achieving An Impressive Image", details: "<h6><em>From our Premium Membership collection, enjoy this free preview! </em></h6><h5>Struggling to Make a Lasting Impression? Tired of Failed First Dates and Missed Opportunities? Stop Wasting Time on Ineffective Style Choices!</h5><p>In this introductory lesson from the Instant Impressive Image series, you will discover the power of an impressive image and learn to make a lasting impression in any situation. You will also unravel the truth behind common misconceptions about men's style and understand the impact of personal appearance on your confidence and success.</p><p>By implementing the strategies outlined in this episode, you will elevate your personal style, exude confidence, and effortlessly command respect in both personal and professional settings.</p><p>We'll cover:</p><p>1. The Impact of Personal Appearance: Understanding the correlation between personal presentation and confidence, and how it affects your overall success.</p><p>2. Timeless Style vs. Fickle Fashion: Embracing the concept of timeless style and learning to make strategic clothing choices that stand the test of time.</p><p>3. The Deep Pareto Principle: Unpacking the 4% of impactful style choices that yield 64% of the desired results, helping you avoid common mistakes and focus on what truly matters.</p>", streamId: "19dd97b577a0353722af4ff6b5da6f58", backdrop: "/backdrops/free-preview-instant-impressive-image-intro.jpg" },
  { slug: "lose-belly-fat-over-40", title: "Lose Belly Fat Over 40", category: "Fitness & Nutrition", categorySlug: "fitness-nutrition", instructorSlugs: ["gav-gillibrand"], thumbnail: "/thumbnails/lose-belly-fat-over-40.png", duration: "42m 22s", access: "free", courseSlug: null, order: null, description: "For Guys Over 40: Get Rid Of Excess Body Fat Around Your Midsection", details: "<p>Join 100's of clients from all over the world who have experienced incredible fat loss, worked hard to lose belly fat (especially those over 40), improved health &amp; fitness and many other life-changing health benefits from working with me on my online coaching programmes.</p><p>Are you next?</p><p>My name is Gav Gillibrand and I’m the guy that helps busy professionals lose belly and unwanted fat over a coaching program of 12 weeks. I help you by making behavioural change coaching, mentoring and a sprinkle of secret wizardry. I specialise in fat loss, body composition &amp; conditioning and I have over 20 years experience as a coach in the health &amp; fitness industry.</p><p>If you are over 40 and struggling to lose belly fat or simply want to look and feel better then please get in touch through my website.</p><p>Go Here ⇒ <a href=\"https://www.youtube.com/redirect?event=video_description&redir_token=QUFFLUhqbmFBUjNWU0liTUh2dGs3aGg2SUl4eDFLVXcyd3xBQ3Jtc0tua1lzRDB3bHM5SGI2Wm8wd1hmQTlSQUFtTWpTdmdpUkNiMUU4RWhXM3g0UGhoX21wZkN0dHViQlZWVFZDelcxbnVnVk8ydTBDbDdkS1dXWHU5WFNxejMxNWNuc3FDUjJBcVlaVVRKZUt4Um9Wd1VWdw&q=http%3A%2F%2Fbit.ly%2Flose-belly-fat-over-40&v=HBqbVJImAD8\" target=\"_blank\">http://bit.ly/lose-belly-fat-over-40</a></p><p><a href=\"https://www.youtube.com/redirect?event=video_description&redir_token=QUFFLUhqbmFBUjNWU0liTUh2dGs3aGg2SUl4eDFLVXcyd3xBQ3Jtc0tua1lzRDB3bHM5SGI2Wm8wd1hmQTlSQUFtTWpTdmdpUkNiMUU4RWhXM3g0UGhoX21wZkN0dHViQlZWVFZDelcxbnVnVk8ydTBDbDdkS1dXWHU5WFNxejMxNWNuc3FDUjJBcVlaVVRKZUt4Um9Wd1VWdw&q=http%3A%2F%2Fbit.ly%2Flose-belly-fat-over-40&v=HBqbVJImAD8\" target=\"_blank\"></a>The beauty of my coaching is the fact that I can work with YOU regardless of location. Many people are scared that they need that “personal touch” and that online coaching won’t work for them. I understand how they feel but this is what I’ve found, losing those unwanted pounds of fat isn't easy, it requires dedication, but if you really do want to lose that belly fat and you are struggling because you are over 40 my coaching could be just what you need.</p><p>In my experience, coaching is far more powerful than standing next to someone and counting their reps. A good coach provides massive acceleration towards your goal, avoiding all the pitfalls, heartache and wasted time and money. You will need to make a significant effort to lose that fat, have you struggled to lose belly fat or weight on your own? Book a call with me now to discover how we can work together.</p><p>Implementation, not information, that’s what you need. No gimmicks or fads, just results based on science and 1000’s of hours of experience.</p><p>Get in touch to find out how we can work together to help you lose that unwanted belly fat, I've helped 100's of people just like you lose the fat and improve their lives.</p>", streamId: "d131ea57cb9f827a592310df72a36b3f", backdrop: "/backdrops/lose-belly-fat-over-40.jpg" },
  { slug: "get-more-matches-on-dating-apps", title: "Get More Matches On Dating Apps", category: "Dating", categorySlug: "dating", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/get-more-matches-on-dating-apps.png", duration: "1h 19m", access: "premium", courseSlug: null, order: null, description: "Getting few responses and matches on dating apps?", details: "<p>Why divorced men over 40 fail to showcase their authentic selves with unflattering or sloppy dating profiles...And if they could, they’d attract kindred spirits by highlighting their alluring essence and life experiences.</p>", streamId: null, backdrop: "/backdrops/get-more-matches-on-dating-apps.jpg" },
  { slug: "stop-killing-your-chances-for-a-second-date", title: "Stop Killing Your Chances For a Second Date", category: "Dating", categorySlug: "dating", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/stop-killing-your-chances-for-a-second-date.png", duration: "1h 22m", access: "free", courseSlug: null, order: null, description: "Noticing women pull away after first dates when you try to secure the next date too quickly?", details: "<p>Attraction Killer: The #1 thing guys do that turn women off instantly and ruin their chances of ever getting a second date.</p><p>Why divorced men over 40 feel stabs of panic watching women politely make excuses when they aggressively lock down the next date...And if they could, they’d embody the emotional security to nonchalantly let first dates unfold without grasping to control outcomes.</p>", streamId: null, backdrop: "/backdrops/stop-killing-your-chances-for-a-second-date.jpg" },
  { slug: "no-more-looking-sloppy-unrefined", title: "No More Looking Sloppy and Unrefined", category: "Image & Style", categorySlug: "image-style", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/no-more-looking-sloppy-unrefined.png", duration: "1h 54m", access: "free", courseSlug: null, order: null, description: "Unimpressed by what you see in the mirror?", details: "<p>Why divorced men over 40 fail to cultivate go-to style systems for elevating their everyday presentation...And if they could, internalized guidelines would make polished refinement their natural default for showcasing impeccable taste.</p>", streamId: null, backdrop: "/backdrops/no-more-looking-sloppy-unrefined.jpg" },
  { slug: "flatter-your-body-type", title: "Flatter Your Body Type", category: "Image & Style", categorySlug: "image-style", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/flatter-your-body-type.png", duration: "1h 20m", access: "free", courseSlug: null, order: null, description: "Stop wearing cuts and fabrics unflattering to your shape, which highlight the stuff you want to minimize", details: "<p>Dressing for Your Body Type: Styles that flatter different physiques.</p><p>Why divorced men over 40 struggle with concealing weight gain and softening features with their clothing choices...And if they could, tailored lines and luxe fabrics would accentuate their best attributes and give an air of success.</p>", streamId: null, backdrop: "/backdrops/flatter-your-body-type.jpg" },
  { slug: "never-get-ghosted-again", title: "Never Get Ghosted Again", category: "Dating", categorySlug: "dating", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/never-get-ghosted-again.png", duration: "1h 8m", access: "premium", courseSlug: null, order: null, description: "Stop wasting time on half-interested women and getting caught off-guard by flaky behavior", details: "<p>Why divorced men over 40 struggle with modern digital dating behaviors like ghosting and breadcrumbing...And if they could, they’d adopt a healthy detachment from outcomes while pursuing romantic possibilities aligned with their standards.</p>", streamId: "87c1c47a776d6cafaec7ac58d26ca857", backdrop: "/backdrops/never-get-ghosted-again.jpg" },
  { slug: "5-ways-to-train-smarter", title: "Train Smarter To Maximise Building Muscle", category: "Fitness & Nutrition", categorySlug: "fitness-nutrition", instructorSlugs: ["aidan-lee"], thumbnail: "/thumbnails/5-ways-to-train-smarter.png", duration: "", access: "free", courseSlug: null, order: null, description: "For Guys Over 40: Build An Elite Physique That Will Last For Life AND Master A Zen State Of Work-Life Balance", details: "<h3>5 Ways To Train Smarter So You Can Maximise Building Muscle With The Right 30 Minute Workouts</h3><p><strong>99% of dads today will never truly Be A Powerful Warrior For Their Families.</strong></p><p>They don’t know what it’s like to achieve their Elite Physique, Zen Work-Life Balance.</p><p>They are too busy drowning in work responsibilities, juggling family commitments, and trying to maintain a work-life balance.</p><p><strong>Their families suffer because they aren’t strong and present role models OR supportive partners for their wives. </strong></p><p>Breaking this cycle is vital.</p><p>This is why I do what I do.</p><p>My students become Powerful Warriors for their families, lead by example, and build a <strong>thriving family legacy</strong>.</p><p>In The Modern Warrior Transformation, you will access the<strong> guidance you need</strong> to <strong>unlock your Elite Physique,</strong> and commit to <strong>being your best self</strong> so you can achieve <strong>lifetime results</strong>.<br><br><a href=\"https://fitroots.co.uk/midlife/\" target=\"_blank\">Click here now to start your TRANSFORMATION!</a></p>", streamId: "eb5514fb1973cb8d4b435886e61576d1", backdrop: "/backdrops/5-ways-to-train-smarter.jpg" },
  { slug: "midlife-dating-unlocked-part-8-avoiding-common-midlife-dating-mistakes", title: "Midlife Dating Unlocked Part 8: Avoiding Common Midlife Dating Mistakes", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-8-avoiding-common-midlife-dating-mistakes.png", duration: "17m 20s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 8, description: "Eliminate Self-Sabotage: Proven Tips for Thriving in the Midlife Dating Scene", details: "<h5>Midlife Dating Mistakes: Stop Sabotaging Your Chances with Women! Avoid These Common Pitfalls and Unlock Incredible New Dating Experiences</h5><p><br>In this lesson of \"Midlife Dating Unlocked,\" we're diving deep into the common mistakes that men in their 40s and 50s make when dating. Learn how to avoid these pitfalls and start connecting with women authentically and effortlessly.</p><p>You’ll gain the knowledge to sidestep typical dating errors, cultivate a positive and genuine approach, and turn your interactions with women into successful, lasting connections.<br></p><p><strong>1. Avoid Being Outcome Dependent:<br></strong> &nbsp; - One major mistake is being fixated on immediate results. Romeo Lewis explains how setting small, manageable goals and focusing on reconnecting with your instincts helps you feel and express your true self without the pressure of instant success.<br> &nbsp; - Understand that rushing into interactions with the goal of getting phone numbers or setting up dates can create anxiety and inauthenticity, which women can sense.</p><p><br><strong>2. Don't Over-Rely on Texts to Build Attraction:<br></strong> &nbsp; - Dean Gladwyn points out that men often make the error of thinking they can build attraction through clever texts after a weak initial meeting.<br> &nbsp; - Learn why a powerful, positive first interaction is far more important, setting the stage so that when you text her, it’s merely to coordinate logistics, not to create connection or attraction.<br></p><p><strong>3. Let Go of the Ego:<br></strong> &nbsp; - Romeo discusses how trying to present a perfect version of yourself or worrying about saying the wrong thing stems from ego, which hinders authentic communication.<br> &nbsp; - Embrace the courage to make mistakes and learn from them. Over time, operating from a place of authenticity will naturally lead to better outcomes with women.</p><p><br>With these insights, you'll be better equipped to navigate the dating scene without falling into these common traps. Embrace authenticity, focus on genuine connections, and see your dating life transform.</p>", streamId: "f9d1956c0bae122c41e4b0fcef088e86", backdrop: "/backdrops/midlife-dating-unlocked-part-8-avoiding-common-midlife-dating-mistakes.jpg" },
  { slug: "midlife-dating-unlocked-part-7-how-to-start-conversations-with-women", title: "Midlife Dating Unlocked Part 7: How To Start Conversations With Women", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-7-how-to-start-conversations-with-women.png", duration: "18m 00s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 7, description: "How to go from struggling to approach women to confidently starting conversations.", details: "<h5>Frustrated with failed pickup lines and rehearsed, phony routines? Stop relying on scripted techniques that don’t work and discover how to start conversations with beautiful women effortlessly.</h5><p><br>In this Midlife Dating Unlocked lesson, you'll learn powerful techniques to genuinely connect with women without falling into the trap of canned pickup lines or awkward job interview-style conversations. Discover how to create a real, lasting impression by being authentically you.<br></p><p>By implementing the insights from this episode, you’ll achieve deeper connections and relationships, making authentic connections that go beyond surface-level interactions. Say goodbye to ineffective dating advice and hello to meaningful connections.<br></p><p><strong>1. Authentic Expression Over Scripted Lines:<br></strong> &nbsp; You'll learn why relying on scripted pickup lines and techniques fails to create genuine connections. Instead, we'll show you how to allow your instinct and authentic expressions to guide your conversations, making you more relatable and attractive to women.</p><p><br><strong>2. Qualifying with a Mindset of Standards:<br></strong> &nbsp; Understand the importance of knowing what you want in a partner and how to communicate that effectively. By qualifying women based on their compatibility with your values and standards, rather than just their looks, you’ll stand out as a man with high standards who values deeper connections.<br></p><p><strong>3. Engaging Conversations Without the Interview Feel:<br></strong> &nbsp; Learn how to maintain flowing, natural conversations that avoid the dreaded interview style. We’ll cover techniques like making observations and sharing personal interests in a way that fosters mutual interest and keeps the conversation engaging and fun. <br></p><p>By focusing on these key points, you will be better equipped to foster genuine, meaningful connections that lead to lasting relationships. </p>", streamId: "70b26155c8f177c4f7c1193e038d2178", backdrop: "/backdrops/midlife-dating-unlocked-part-7-how-to-start-conversations-with-women.jpg" },
  { slug: "midlife-dating-unlocked-part-6-the-truth-about-high-status-high-value", title: "Midlife Dating Unlocked Part 6: The Truth About \"High Status\" & \"High Value\"", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-6-the-truth-about-high-status-high-value.png", duration: "15m 12s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 6, description: "Forget what the manosphere teaches about status and value. Here's the real truth.", details: "<h5>Fed up with feeling invisible and insecure in your midlife dating journey? Stop chasing high status and external validation—it's time to unlock the true secret to attracting genuine connections.</h5><p>In this Midlife Dating Unlocked lesson, we'll reveal how to break free from social conditioning and societal misconceptions about status and value, enabling you to connect authentically and naturally with potential partners.</p><p>By the end of this video, you'll understand how to harness your true, authentic self to build meaningful relationships, regardless of age, looks, or social standing.<br></p><p><strong>1. Letting Go of the Outcome:<br></strong> &nbsp; - Discover why detaching yourself from the pressures of meeting women is crucial.<br> &nbsp; - Learn how focusing on self-connection and enjoying the moment can naturally enhance your social skills and make you more attractive.<br> &nbsp; - Understand the principle that being present in each interaction fosters genuine connections.<br><strong>2. Redefining Status and Value:<br></strong> &nbsp; - Debunk the myths that societal measures like looks, money, and status dictate romantic success.<br> &nbsp; - Explore real-life examples of men who, despite having 'dad bods' or being shorter, attract incredible partners due to their authenticity and self-confidence.<br> &nbsp; - Gain insights into the real, intrinsic traits that women find irresistible, like playfulness, confidence, and authenticity.<br><strong>3. Harnessing Authenticity:<br></strong> &nbsp; - Delve into practical advice on how to be your true self and express that openly.<br> &nbsp; - Learn strategies to cultivate self-worth and internal validation, which naturally radiates and draws others to you.<br> &nbsp; - Be inspired by stories of individuals who have unlocked their authentic selves to find fulfilling relationships.<br></p><p>By focusing on these three pivotal ideas, you'll reshape your midlife dating approach and begin to attract high-quality, genuine connections. </p>", streamId: "12fc3a4698dd009074569744ce08eadd", backdrop: "/backdrops/midlife-dating-unlocked-part-6-the-truth-about-high-status-high-value.jpg" },
  { slug: "midlife-dating-unlocked-part-5-obliterate-nervousness-overthinking-anxiety", title: "Midlife Dating Unlocked Part 5: Obliterate Nervousness, Overthinking, & Anxiety", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-5-obliterate-nervousness-overthinking-anxiety.png", duration: "15m 16s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 5, description: "How to go from feeling nervous around beautiful women to to effortlessly striking up conversations with ease", details: "<h5>Struggling to approach attractive women without feeling a cold sweat down your neck and stumbling over your words? Stop relying on pickup lines and 'confidence hacks' that leave you feeling more awkward and rejected!</h5><p><br>In this M, you'll learn why those common tactics are failing you and discover a transformative approach to engaging with women confidently by reconnecting with your true self.<br></p><p>Imagine being able to walk into any social situation, effortlessly starting conversations with attractive women, and having them naturally gravitate towards you, all while feeling genuinely comfortable and authentic.<br></p><p>1. Reclaiming Your True Self: Learn how to tap into the natural confidence you had as a child before ego and societal pressures took over. We’ll delve into the concept of the 'true self' and how believing in it frees you from the anxiety and self-doubt holding you back.</p><p><br>2. Ditching the Ego: Discover the pitfalls of operating from a place of ego and attempt to memorize pickup lines. Instead, get practical insights into expressing yourself authentically and why this creates a more genuine and magnetic presence.</p><p><br>3. The Power of Vibing: Understand the importance of enjoying yourself and creating a positive vibe. This section will show you how to blend into social settings effortlessly, leading to spontaneous and natural interactions with women that are both respectful and effective.</p>", streamId: "4b28b4dd150b693ad79facfa8cf718da", backdrop: "/backdrops/midlife-dating-unlocked-part-5-obliterate-nervousness-overthinking-anxiety.jpg" },
  { slug: "midlife-dating-unlocked-part-4-approaching-women-rejection-free", title: "Midlife Dating Unlocked Part 4: Approaching Women Rejection-Free", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-4-approaching-women-rejection-free.png", duration: "16m 23s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 4, description: "Enhance your dating game without resorting to gimmicks or rehearsed lines", details: "<h5>Struggling with Approaching Women? Stop Letting Fear Sabotage Your Confidence!</h5><p>Discover how to overcome common mindsets that are holding you back and master the skill of approaching women with confidence and authenticity.<br></p><p>By implementing the strategies discussed, you'll become more comfortable and successful in social settings and develop genuine connections without the fear of rejection or self-doubt.</p><p><br><strong>1. Understanding the Spotlight Effect:</strong></p><p>- Learn why you feel everyone is watching and judging you in social settings.</p><p>- Discover how to depersonalize this feeling and realize it’s a common affliction, not a personal shortcoming.</p><p>- Find out effective strategies to combat the spotlight effect and free yourself from the crippling fear of public criticism.</p><p><strong>2. Reframing Rejection:</strong></p><p>- Understand why rejection isn't a reflection of your worth or character.</p><p>- Learn how to view rejections objectively and recognize external factors that could influence a woman's response.</p><p>- Replace personalizing rejection with a more detached, constructive perspective, helping you to stay motivated.</p><p><strong>3. Building Authentic Confidence:</strong></p><p>- Grasp why relying on pickup lines and scripts can backfire and how true confidence stems from authenticity.</p><p>- Learn how to use situational inspiration to start genuine conversations with women.</p><p>- Discover methods to celebrate actions over outcomes, training your brain to find confidence in the effort, not the external results.</p><p>Dismantle the myths and misconceptions that have been holding you back, and unlock the authentic, confident version of yourself that can approach women naturally and successfully!</p>", streamId: "bb2f3bd5bc5f7e9e589d479567268211", backdrop: "/backdrops/midlife-dating-unlocked-part-4-approaching-women-rejection-free.jpg" },
  { slug: "midlife-dating-unlocked-part-3-uncovering-your-true-identity", title: "Midlife Dating Unlocked Part 3: Uncovering Your True Identity", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-3-uncovering-your-true-identity.png", duration: "14m 23s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 3, description: "Rediscovering Your True Self Post-Divorce", details: "<h5>Struggling to Feel Whole Again? Stop Clinging to Your Old Identity and Start Reconnecting with Your True Self!</h5><p><br>In this video, we’ll unveil the transformative steps you can take to truly discover your authentic self after long-term relationships. Gain insights into why your old approach isn't working and how you can finally feel whole and genuine again.<br></p><p>By the end of this video, you will have a clear understanding of how to navigate your inner world, separate yourself from past conditioning, and embrace a new, unconstrained you, enabling deeper self-connection and more fulfilling relationships.<br></p><p><strong>1. The Three Parts of Self-Identity:<br></strong> &nbsp; &nbsp;- Discover how to differentiate between who you think you are (your ego), your instinctual self, and the inner critic that holds you back. Learn techniques to stop identifying with restrictive labels and start operating from a place of true self-expression.</p><p><br><strong>2. Confronting Social Conditioning:<br></strong> &nbsp; &nbsp;- Uncover the ways social conditioning and past traumas create a negative internal dialogue that stifles confidence and peace. Dean Gladwyn and Romeo Lewis explain practical methods to observe these thoughts and emotions, allowing you to neutralize and transform them into positivity.</p><p><br><strong>3. Practical Steps to Reclaiming Joy and Authenticity:<br></strong> &nbsp; &nbsp;- Get actionable advice on how to begin enjoying your own company, overcoming social anxiety, and attracting positive interactions organically. Learn to bring your own party and build genuine connections without relying on superficial techniques.<br></p>", streamId: "608d8d1c0b9c3917d52797345fa88d0b", backdrop: "/backdrops/midlife-dating-unlocked-part-3-uncovering-your-true-identity.jpg" },
  { slug: "midlife-dating-unlocked-part-2-no-faking-authentic-confidence", title: "Midlife Dating Unlocked Part 2: No-Faking, Authentic Confidence", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-2-no-faking-authentic-confidence.png", duration: "11m 42s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 2, description: "Midlife Dating Success: Boosting Confidence and Emotional Health", details: "<h5>Struggling with Attracting Quality Women After 40? Stop Chasing Quick Fixes and Start Building True Confidence</h5><p><br>In part two of the Midlife Dating Unlocked Masterclass, you'll learn the secret to attracting the right women by building sustainable confidence and self-esteem through healthy routines and self-optimization.</p><p><br>You will become a self-sufficient, confident man who naturally attracts the kind of woman you desire, creating a foundation for a healthier and more fulfilling relationship.</p><p><br><strong>1. The Importance of Self-Optimization:<br></strong> &nbsp; Dean Gladwyn emphasizes the necessity of being mentally, emotionally, and physically ready before jumping into the dating pool. True confidence comes from within and is amplified through disciplined habits such as regular gym workouts, a nutritious diet, meditation, and staying off quick dopamine fixes like pornography. These habits build self-esteem and emotional stability, making you more attractive and charismatic.</p><p><br><strong>2. The Pitfall of Seeking External Validation:<br></strong> &nbsp; Romeo Lewis shares his personal experience of seeking validation from women and how it led to temporary success and eventual dissatisfaction. He highlights the importance of knowing what you want and becoming the best version of yourself first, rather than relying on pickup lines and superficial tactics.</p><p><br><strong>3. Healthy Mindset and Self-Care:<br></strong> &nbsp; The conversation takes a deeper dive into recognizing and managing feelings of guilt, especially after a divorce. Lee Nazal and Romeo Lewis offer insights on transitioning from focusing on others to prioritizing self-care. They also stress the value of maintaining hobbies and passions for long-term personal growth and relationship health.</p><p><br>By integrating these practices, you'll move beyond quick fixes and adopt a holistic approach to becoming your best self, attracting the right partner naturally.</p>", streamId: "39c5e272b97fad12f58d14d19e428c1b", backdrop: "/backdrops/midlife-dating-unlocked-part-2-no-faking-authentic-confidence.jpg" },
  { slug: "midlife-dating-unlocked-part-1-the-first-step-before-dating", title: "Midlife Dating Unlocked Part 1: The First Step Before Dating", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-part-1-the-first-step-before-dating.png", duration: "15m 07s", access: "premium", courseSlug: "midlife-dating-unlocked", order: 1, description: "Step One in Post-Divorce Dating: Rebuilding Self-Esteem and Finding Your Ideal Partner", details: "<h5>Divorced and Lost? Quit Rushing Into New Relationships Only to Fail Again!</h5><p><br>In part 1 of the Midlife Dating Unlocked Masterclass series, we’re going to unveil the critical first step to take before jumping back into the dating scene post-divorce. Discover how to rebuild your self-esteem and identify the right partner so you won’t repeat past mistakes.<br></p><p>By following the advice in this video, you’ll gain clarity and confidence, ensuring that your next relationship is healthier, fulfilling, and long-lasting.<br></p><p><strong>1. Reconnect with Yourself:<br></strong> &nbsp; Before diving into the dating pool, take the time to rediscover who you are and what you loved before your marriage. This serves as the foundational step to regaining your self-worth and preparing for new relationships.<br></p><p><strong>2. Define Your Ideal Partner:<br></strong> &nbsp; Spend adequate time in detailing the characteristics, behaviors, and interests of your ideal partner. This isn’t just about physical traits but aligning on hobbies, values, and life goals to ensure a deeper and more meaningful connection.<br></p><p><strong>3. Set Clear Goals and Standards:<br></strong> &nbsp; Understand what you’re truly looking for in a relationship to avoid falling back into unhealthy cycles. Knowing your preferences and deal-breakers helps in making better choices and finding a partner who truly complements you, thereby increasing the chances of a successful, long-term relationship.</p>", streamId: "f8cc7f2ff3cd9ef2cb9fcb14a6c03f0e", backdrop: "/backdrops/midlife-dating-unlocked-part-1-the-first-step-before-dating.jpg" },
  { slug: "midlife-dating-unlocked-intro-the-ultimate-strategy-for-men-over-40", title: "Midlife Dating Unlocked Intro: The Ultimate Strategy For Men Over 40", category: "Dating", categorySlug: "dating", instructorSlugs: ["dean-gladwyn", "romeo-lewis"], thumbnail: "/thumbnails/midlife-dating-unlocked-intro-the-ultimate-strategy-for-men-over-40.png", duration: "21m 19s", access: "premium", courseSlug: "midlife-dating-unlocked", order: null, description: "The Ultimate Dating Strategy For Men Over 40", details: "<h5>Divorced and Struggling to Attract Women Over 40? Stop Believing You Need a Six-Pack and a Fat Wallet!<br></h5><p>In &nbsp;masterclass, we’ll reveal how men over 40 can cultivate genuine confidence and attract beautiful women without relying on outdated beliefs about money or muscles. <br><br>By the end of this episode, you’ll have the tools to unlock your potential, build deep connections with women, and transform your midlife dating experience—regardless of your past struggles.<br></p><p>1. <strong>Understanding the New Dating Landscape:</strong><br> &nbsp; - Discover how the dating game has changed since your last relationship, and why traditional methods may no longer work. We'll delve into the impact of social media and dating apps, and why being your genuine self is more important than ever.<br></p><p>2. <strong>Building Genuine Confidence:</strong><br> &nbsp; - Learn actionable steps to boost your self-esteem and social skills. We’ll share insights on how self-improvement, rather than superficial attributes like money or looks, is the key to attracting the right women.<br></p><p>3. <strong>Executing Effective Approaches</strong>:<br> &nbsp; - Get practical advice on how to approach women confidently and create a meaningful connection. We’ll break down the barriers that hold you back and provide you with a clear methodology to navigate midlife dating successfully.<br> &nbsp; &nbsp;</p>", streamId: "bd5504dafc5c7a7947f04ed6229b1762", backdrop: "/backdrops/midlife-dating-unlocked-intro-the-ultimate-strategy-for-men-over-40.jpg" },
  { slug: "midlife-masculinity-unlocked-part-4-make-it-happen", title: "Midlife Masculinity Unlocked Part 4: Make It Happen", category: "Masculinity", categorySlug: "masculinity", instructorSlugs: ["dan-lavoie"], thumbnail: "/thumbnails/midlife-masculinity-unlocked-part-4-make-it-happen.png", duration: "21m 19s", access: "premium", courseSlug: "midlife-masculinity-unlocked", order: 3, description: "How To Get Out Of A Rut Without Needing Motivation", details: "<h5>Blast through complacency and gain positive momentum do get your life back on track</h5><p>It's easy to give up on yourself and stop trying after divorce. Your world has crashed down all around you, you're lost, and you don't know where to start. We'll show you the best way to get over that inertia so you can get back out there and start kicking ass again!</p><p>This lesson is Part 4 of the Midlife Masculinity Unlocked series, where you'll discover how you can:</p><ul><li>Go From Struggling with Self-Worth to Discovering Your Inner Potential and Confidence</li><li>Go From Being Unable to Enforce Healthy Boundaries to Commanding Respect and Trust</li><li>Go From Failing to Recover from Setbacks to Building Unshakable Mental Resilience</li><li>Go From Struggling with People-Pleasing to Asserting Your Needs and Living Authentically</li></ul><p>Embrace a life where past struggles are stepping stones to a powerful self-image, motivating relationships, and an adventurous day-to-day existence that you control.</p><p>We cover:</p><ol><li><strong>Unlocking Self-Respect</strong>: Dive into Dan Lavoie's critical steps for personal growth that shift your mindset away from trying to please everyone else. Explore the simple tools to reclaim your place in your own life and cultivate a resilient, unshakeable sense of self.</li><li><strong>Strategic Recovery</strong>: Dan's approach focuses on mental strength and resilience techniques to foster rapid return to success, enabling you to live life on your own terms, unswayed by the fleeting opinions of others.</li><li><strong>Living the Adventure</strong>: Get inspired by the coaching strategies Dan provides to inject excitement back into your life. Rediscover hobbies, plan for balanced family adventures, and assess job satisfaction, elevating your lifestyle from mere survival to thriving in a life you absolutely love.</li></ol>", streamId: "38af67c79cc897c82d07879222803f96", backdrop: "/backdrops/midlife-masculinity-unlocked-part-4-make-it-happen.jpg" },
  { slug: "midlife-masculinity-unlocked-part-3-live-like-an-adventure", title: "Midlife Masculinity Unlocked Part 3: Live Like An Adventure", category: "Masculinity", categorySlug: "masculinity", instructorSlugs: ["dan-lavoie"], thumbnail: "/thumbnails/midlife-masculinity-unlocked-part-3-live-like-an-adventure.png", duration: "21m 19s", access: "premium", courseSlug: "midlife-masculinity-unlocked", order: 3, description: "Design And Live The Awesome, Happy Life You Were Meant To Live", details: "<h5>Don't get so focused on making a living that you actually forget to live.</h5><p>Most of us get bogged down in the daily grind. We're busy eking out a living, providing for our families, and making sure everyone is safe and secure. Rinse and repeat. But in the process, you neglect yourself. You neglect actually living. Bringing spice to your life. And if there's no spice, what's the fucking point? This video helps you get out of that trap and start living.</p><p>This lesson is Part 3 of the Midlife Masculinity Unlocked series, where you'll discover how you can:</p><ul><li>Go From Struggling with Self-Worth to Discovering Your Inner Potential and Confidence</li><li>Go From Being Unable to Enforce Healthy Boundaries to Commanding Respect and Trust</li><li>Go From Failing to Recover from Setbacks to Building Unshakable Mental Resilience</li><li>Go From Struggling with People-Pleasing to Asserting Your Needs and Living Authentically</li></ul><p>Embrace a life where past struggles are stepping stones to a powerful self-image, motivating relationships, and an adventurous day-to-day existence that you control.</p><p>We cover:</p><ol><li><strong>Unlocking Self-Respect</strong>: Dive into Dan Lavoie's critical steps for personal growth that shift your mindset away from trying to please everyone else. Explore the simple tools to reclaim your place in your own life and cultivate a resilient, unshakeable sense of self.</li><li><strong>Strategic Recovery</strong>: Dan's approach focuses on mental strength and resilience techniques to foster rapid return to success, enabling you to live life on your own terms, unswayed by the fleeting opinions of others.</li><li><strong>Living the Adventure</strong>: Get inspired by the coaching strategies Dan provides to inject excitement back into your life. Rediscover hobbies, plan for balanced family adventures, and assess job satisfaction, elevating your lifestyle from mere survival to thriving in a life you absolutely love.</li></ol>", streamId: "14984a632a6ae008da6b0f885e205367", backdrop: "/backdrops/midlife-masculinity-unlocked-part-3-live-like-an-adventure.jpg" },
  { slug: "midlife-masculinity-unlocked-part-2-boundaries", title: "Midlife Masculinity Unlocked Part 2: Boundaries", category: "Masculinity", categorySlug: "masculinity", instructorSlugs: ["dan-lavoie"], thumbnail: "/thumbnails/midlife-masculinity-unlocked-part-2-boundaries.png", duration: "21m 19s", access: "premium", courseSlug: "midlife-masculinity-unlocked", order: 2, description: "Command Respect And Never Take Shit From Anyone Ever Again", details: "<h5>The power of establishing and enforcing boundaries</h5><p>Before your divorce, you were probably a people pleaser. You let people walk all over you, most of all your ex. Coach Dan Lavoie teaches you how to make sure no one ever disrespects you again. Whether it's friends, family, a date, or a significant other, you'll learn the secret to setting boundaries that they have no choice but to honor.<br><br>This lesson is Part 2 of the Midlife Masculinity Unlocked series, where you'll discover how you can:</p><ul><li>Go From Struggling with Self-Worth to Discovering Your Inner Potential and Confidence</li><li>Go From Being Unable to Enforce Healthy Boundaries to Commanding Respect and Trust</li><li>Go From Failing to Recover from Setbacks to Building Unshakable Mental Resilience</li><li>Go From Struggling with People-Pleasing to Asserting Your Needs and Living Authentically</li></ul><p>Embrace a life where past struggles are stepping stones to a powerful self-image, motivating relationships, and an adventurous day-to-day existence that you control.</p><p>We cover:</p><ol><li><strong>Unlocking Self-Respect</strong>: Dive into Dan Lavoie's critical steps for personal growth that shift your mindset away from trying to please everyone else. Explore the simple tools to reclaim your place in your own life and cultivate a resilient, unshakeable sense of self.</li><li><strong>Strategic Recovery</strong>: Dan's approach focuses on mental strength and resilience techniques to foster rapid return to success, enabling you to live life on your own terms, unswayed by the fleeting opinions of others.</li><li><strong>Living the Adventure</strong>: Get inspired by the coaching strategies Dan provides to inject excitement back into your life. Rediscover hobbies, plan for balanced family adventures, and assess job satisfaction, elevating your lifestyle from mere survival to thriving in a life you absolutely love.</li></ol>", streamId: "96466daf5be4e4b0e499f0d02c742c24", backdrop: "/backdrops/midlife-masculinity-unlocked-part-2-boundaries.jpg" },
  { slug: "midlife-masculinity-unlocked-part-1-intro", title: "Midlife Masculinity Unlocked Part 1: Reclaim Your Masculinity", category: "Masculinity", categorySlug: "masculinity", instructorSlugs: ["dan-lavoie"], thumbnail: "/thumbnails/midlife-masculinity-unlocked-part-1-intro.png", duration: "21m 19s", access: "premium", courseSlug: "midlife-masculinity-unlocked", order: 1, description: "The First Step To Being Your Own Man Again After Divorce", details: "<h5>Why do men over 40 struggle to feel like they're good enough after divorce?</h5><p>In this introductory lesson from the Midlife Masculinity Unlocked series, you'll discover how you can:</p><ul><li>Go From Struggling with Self-Worth to Discovering Your Inner Potential and Confidence</li><li>Go From Being Unable to Enforce Healthy Boundaries to Commanding Respect and Trust</li><li>Go From Failing to Recover from Setbacks to Building Unshakable Mental Resilience</li><li>Go From Struggling with People-Pleasing to Asserting Your Needs and Living Authentically</li></ul><p>Embrace a life where past struggles are stepping stones to a powerful self-image, motivating relationships, and an adventurous day-to-day existence that you control.</p><p>We cover:</p><ol><li><strong>Unlocking Self-Respect</strong>: Dive into Dan Lavoie's critical steps for personal growth that shift your mindset away from trying to please everyone else. Explore the simple tools to reclaim your place in your own life and cultivate a resilient, unshakeable sense of self.</li><li><strong>Strategic Recovery</strong>: Dan's approach focuses on mental strength and resilience techniques to foster rapid return to success, enabling you to live life on your own terms, unswayed by the fleeting opinions of others.</li><li><strong>Living the Adventure</strong>: Get inspired by the coaching strategies Dan provides to inject excitement back into your life. Rediscover hobbies, plan for balanced family adventures, and assess job satisfaction, elevating your lifestyle from mere survival to thriving in a life you absolutely love.</li></ol>", streamId: "8c2f4c74f87c423db4d3b698c1c69bfe", backdrop: "/backdrops/midlife-masculinity-unlocked-part-1-intro.jpg" },
  { slug: "midlife-strength-unlocked-lesson-1-intro", title: "Midlife Strength Unlocked Part 1: Transform Your Dad Bod", category: "Fitness & Nutrition", categorySlug: "fitness-nutrition", instructorSlugs: ["aidan-lee"], thumbnail: "/thumbnails/midlife-strength-unlocked-lesson-1-intro.png", duration: "11m 36s", access: "premium", courseSlug: "midlife-strength-unlocked", order: 1, description: "Guys Over 40: The Counter-Intuitive Way To Transform Your Dad Bod", details: "<h5>How to go from a big-belly dad bod to a sleek, muscular \"Daddy\" bod, specifically for guys over 40</h5><p>In this introduction to the Midlife Strength Unlocked series, join functional strength and martial arts expert Aidan Lee as he shows men over 40 how to go from struggling with good health to achieving a Warrior's physique and work-life balance.</p><p>The first rule is, if you're over 40, you can't train like you did in your twenties. So if you're doing CrossFit, yoga, bodybuilding routines, or even boot camps, before your next session, STOP&nbsp;RIGHT&nbsp;NOW!</p><p>You'll discover a revolutionary approach that transcends traditional weight loss and muscle-building methods and taps into the holistic connection between posture, mind, and muscle. </p><p>It's not just an upgrade for your looks, but also an all-outwellness transformation.</p><p>Embrace the journey toward a warrior's physique and zen-like work-life balance, mastering functional movements that align with your body's natural mechanics, fostering resilience against age-related decline, and unlocking an invigorated sense of self that permeates through every facet of your life.</p><p>We cover:</p><ol><li><strong>Holistic Posture Alignment:</strong> Dive deep into Aidan Lee's insights on why your posture is the silent linchpin to long-term health and how addressing your alignment is about more than just looking good – it's about feeling strong, mobile, and youthful as you age.</li><li><strong>Functional Strength Training:</strong> Discover the power of integrating strength training with mindful movement, focusing on compound, multi-joint exercises that mimic real-life activities. Aidan Lee will debunk the myths of isolated single-muscle workouts and show you how to engage in a smarter, full-body approach that conditions your body to move as one efficient, powerful unit.</li><li><strong>Mental Grit and Philosophy in Fitness:</strong> Learn how the ancient wisdom from texts such as \"The Art of War\" and \"The Book of Five Rings\" can elevate your training and life strategies, as Aidan Lee explains the profound impact of incorporating a warrior’s mindset into your daily routine, especially when tackling the challenges of health, divorce, and mid-life transformation.</li></ol>", streamId: "2f96c07a9cc6fdbcd2273b6457323ab7", backdrop: "/backdrops/midlife-strength-unlocked-lesson-1-intro.jpg" },
  { slug: "overcoming-fear-anxiety", title: "Overcoming Fear & Anxiety", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/overcoming-fear-anxiety.png", duration: "23m 21s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 2, description: "Never Let Fear & Anxiety Hold You Back In Any Situation Ever Again", details: "<h5>Are you tired of being held back by fear and anxiety in crucial situations? Sick of trying to eliminate these emotions and failing every time?</h5><p>How many opportunities have you missed in your life because you were afraid to take action? </p><p>You might have met your dream woman. You might have landed your dream client. You might have been promoted faster. Instead, all you feel is the pain of regret, wondering what might have been.</p><p>Discover how to harness fear and anxiety to work for you, rather than against you. Learn practical steps to overcome your fears and confidently tackle any situation.</p><p>You will gain the confidence to face your fears and navigate through challenging situations with ease. </p><p>1. Overcoming fear and anxiety is not about eliminating them, but about acting in spite of them. Learn how to harness these emotions to make them work for you, rather than against you.</p><p>2. Practice and skill play a crucial role in managing fear and anxiety. Incremental improvements over time can significantly boost confidence and effectiveness in tackling challenging situations.</p><p>3. Gain insights into the importance of outcome independence, practice, and developing the right perspective to conquer fear and anxiety. Real-life experiences and practical examples will illustrate how to apply these principles effectively in various scenarios.</p>", streamId: "f0bacf02e94f48eab5990ea0e2e043c2", backdrop: "/backdrops/overcoming-fear-anxiety.jpg" },
  { slug: "results-agnostic", title: "Develop A Results Agnostic Mindset", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/results-agnostic.png", duration: "19m 27s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 3, description: "Life-Changing Secret: How To Not Give A F*ck", details: "<h5>The Game-Changing Mindset for Unstoppable Confidence and Success</h5><p>Being outcome independent means being agnostic to the results of any one endeavor.</p><p>This workshop is a must-watch if you're going through:</p><ul><li>Constantly seeking validation from others.</li><li>Worrying about what others think of you.</li><li>Feeling anxious or stressed when facing setbacks or challenges.</li><li>Overly fixated on specific outcomes in personal or professional life.</li><li>Feeling the need to prove yourself to others.</li><li>Avoiding taking risks or pursuing new opportunities out of fear of failure.</li><li>Finding it difficult to assert your own opinions and preferences in social or professional situations.</li><li>Personal relationships being negatively affected by the fear of rejection or disappointment.</li></ul><p>You will discover an approach that frees you from the shackles of fixating on outcomes. Learn how to shift your focus to the process, gain confidence, and never look back.</p><p>Embracing outcome independence will enable you to develop a resilient mindset, navigate setbacks with ease, and consistently progress towards anything you want:</p><ul><li>Meeting beautiful women</li><li>Landing major business deals</li><li>Increasing your income</li><li>Mastering a skill, hobby, or sport...</li></ul><p>...Without being emotionally swayed by temporary setbacks.</p>", streamId: "dd914ee868aa2d3738a0dd48b960fbc0", backdrop: "/backdrops/results-agnostic.jpg" },
  { slug: "100-shots", title: "100 Shots", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/100-shots.png", duration: "", access: "premium", courseSlug: "double-your-job-offers", order: 5, description: "Say Goodbye To Blasting Resumes! Discover The Proven Method To Stand Out In The Job Market And Secure The Job You've Always Wanted", details: "<p>A unique approach to finding your dream job that goes beyond the traditional job search. We delve into a method designed to help you get a leg up in the job market, connect with companies you genuinely want to work for, and increase your chances of landing your ideal role.</p><p>The 100 Shots lesson provides a roadmap for job seekers and career changers to navigate the job market more effectively. By implementing the strategies outlined in this lesson, individuals can enhance their job search efforts, increase their visibility to their dream employers, and ultimately secure rewarding career opportunities.</p>", streamId: "f27b2de6adc301494f1339166ca7330e", backdrop: "/backdrops/100-shots.jpg" },
  { slug: "solutionize", title: "Solutionize", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/solutionize.png", duration: "", access: "premium", courseSlug: "double-your-job-offers", order: 4, description: "Discover A New Perspective On Job Hunting That Could Greatly Increase Your Chances Of Standing Out To Potential Employers", details: "<p>Solutionizing involves flipping the traditional job hiring process on its head and focusing on presenting yourself as a solution to the employer's needs, rather than simply emphasizing your work history and skills.</p><p>The typical hiring process focuses on the job seeker's history and resume, while overlooking the employer's needs and desired outcomes. Understanding the employer's perspective is crucial for standing out in the hiring process.</p><p>Dive deep into the hiring process and learn how to solutionize your approach to make employers notice you. Discover the power of articulating your value through a product value statement and gain a competitive edge, regardless of your work experience.</p>", streamId: "a8e89d98331f40c5a38dd23e51241363", backdrop: "/backdrops/solutionize.jpg" },
  { slug: "outcome-independence", title: "Outcome Independence", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/outcome-independence.png", duration: "", access: "premium", courseSlug: "double-your-job-offers", order: 3, description: "A Powerful And Practical Framework Vital For Building Confidence, Navigating Challenges, And Achieving Success In Both Personal And Professional Spheres", details: "<p>Outcome independence is about not letting the results of our actions dictate our self-worth or confidence. It stresses the importance of embracing the losses, setbacks, and failures as part of the journey towards success. Just like in professional sports, where even the best teams experience losses, individuals should remain focused on the prize while understanding that some losses are inevitable.</p><p>The concept of process-based thinking versus results-based thinking is a cornerstone of outcome independence. It emphasizes the significance of focusing on the process rather than solely fixating on the end result. By adopting a process-based approach, individuals can develop the necessary skills and mindset for long-term success. This perspective is likened to the idea of losing weight, where focusing on the daily efforts and habits is more effective than obsessing over the number on the scale.</p>", streamId: "99309af56f1c891e8eedf384bde68498", backdrop: "/backdrops/outcome-independence.jpg" },
  { slug: "play-your-aces", title: "Play Your Aces", category: "Business & Career", categorySlug: "business-and-career", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/play-your-aces.png", duration: "", access: "premium", courseSlug: "double-your-job-offers", order: 2, description: "Learn To Recognize And Leverage Your Unique Strengths And Experiences To Stand Out In The Job Market", details: "<p>In lesson 2 of the Double Your Job Offers course, we dive into the concept of \"playing your aces\" in your career transition. You'll gain a deeper understanding of the importance of knowing and leveraging their unique life experiences. From uncovering personal strengths to overcoming challenges, this lesson provides valuable insight into how to utilize one's individual journey in a career context. Watch now to discover how understanding and utilizing your aces can give you a distinct advantage in your career transition.</p>", streamId: "0f194a84238825085568fe8c9b2211cb", backdrop: "/backdrops/play-your-aces.jpg" },
  { slug: "posture-and-stance", title: "Convey Confidence Through Body Language", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/posture-and-stance.png", duration: "9m 19s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 8, description: "Body Language Decoded: How To Go From Projecting Weakness And Fear To Exuding Strength, Confidence, And Self-Assurance", details: "<h5>Tired of conveying weakness and neediness? Stop slouching and start commanding respect with your posture and stance...</h5><p>I'll show you why feeling powerless is not going to change until you change your posture and stance. You'll discover how to convey confidence through your body language, and command respect without saying a word.</p><p>Become the confident and commanding figure you want to be, both in your personal and professional life.</p><ul><li>Shift from feeling unsure and insecure to projecting confidence and authority through your body language.</li><li>Eliminate giving off defensive signals and become more open and approachable in social interactions.</li><li>Go from feeling awkward and unsure to projecting confidence and authority through your stance and posture.</li></ul><h2></h2>", streamId: "09aadc68f13d2eb5c6879ff8fc8cf174", backdrop: "/backdrops/posture-and-stance.jpg" },
  { slug: "your-hands-and-eyes", title: "Decoding Their True Intentions", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/your-hands-and-eyes.png", duration: "12m 10s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 3, description: "Body Language Decoded: How To Read Minds By Reading The Eyes And Hands", details: "<h5>Go from feeling disconnected to confidently understanding people's thoughts and intentions, connecting with others authentically.</h5><p><br>You'll understand why your current approach to body language and communication may not be working as effectively as you'd like. You'll discover the power to \"read minds\" by decoding the subtle cues of hands and eyes, leading to improved understanding and interaction with others.</p><p>We'll explore the powerful signals conveyed through hand gestures and eye movements. Throughout this lesson, we'll uncover the hidden meanings behind various hand gestures and discern the significance of different eye gazes. As we unravel these non-verbal cues, you'll gain a remarkable insight into people's thoughts and emotions. </p><p>By implementing the insights from this lesson, you'll gain the ability to interpret the unspoken thoughts and feelings of others through their hand gestures and eye movements.</p><ul><li>Decoding Hand Gestures - Uncover the hidden meanings behind hand positions and movements, and learn to identify signals of cooperation, submissiveness, aggressiveness, and receptiveness in others.</li><li>The Truth About Eye Movements - Understand the significance of pupil dilation, gaze direction, and blinking patterns, and how these can reveal genuine interest, information processing, and even potential deception.</li><li>Harnessing the Power of Nonverbal Communication - Learn how to use open palm gestures to invite cooperation, recognize defensive postures, and effectively communicate with others through your own body language.</li></ul><h2></h2>", streamId: "dbcb7f9d72f1f52f8b5969663e57c060", backdrop: "/backdrops/your-hands-and-eyes.jpg" },
  { slug: "etiquette", title: "Confident Interactions With Proper Etiquette", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/etiquette.png", duration: "13m 14s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 4, description: "Polish Your Professional And Social Etiquette For Confident Interactions", details: "<h5>Fed up with awkward interactions? Overcome social and professional etiquette challenges with ease.</h5><p>You'll understand why the traditional approach to etiquette often leads to discomfort and awkwardness in social and business settings. Discover the keys to effortlessly navigating various scenarios and exuding confidence through polished etiquette.</p><p>You'll transform into a poised and confident individual who commands respect and admiration in social and professional circles.</p><ul><li>Understanding that etiquette is not simply about following rules, but a way of thought and behavior that promotes positive interactions and contributions to society.</li><li>Cultivating thoughtfulness to make a positive impact on others while navigating various social and professional scenarios.</li><li>Building confidence by knowing and embodying your standards and boundaries, leading to smooth and natural interactions based on respect and dignity.</li></ul><h2></h2>", streamId: "fb46f1649fd1778f6c61862306ad649b", backdrop: "/backdrops/etiquette.jpg" },
  { slug: "epic-mission", title: "Mission Statement Workshop: The Key To An EPIC Life", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/epic-mission.png", duration: "26m 15s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 5, description: "Why You Need An EPIC Mission Statement To Live Your Best Possible Life Without Taking Shit From Anyone", details: "<h5>Why do many men lack a clear direction and purpose in life, especially after divorce?</h5><p><br>Do any of these sound like you?</p><ul><li>Waking up feeling aimless and lacking purpose.</li><li>Consistently feeling unfulfilled in their personal and professional life.</li><li>Feeling lost and uncertain about their life's direction.</li><li>Experiencing a lack of motivation and drive to pursue their goals.</li><li>Hiding their true desires and aspirations from their loved ones.</li><li>Lacking clarity and focus in their decision-making processes.</li></ul><p>In this workshop, you'll learn:</p><ul><li>How to go from feeling lost after divorce to creating an impactful mission</li><li>How to go from aimlessly wandering through life to discovering your driving force</li><li>How to go from lacking direction to honing in on your true purpose</li><li>How to go from mere platitudes to crafting a real, impactful mission statement</li></ul><p>Discover how to craft an EPIC mission statement that drives your life forward and gives it meaning, resulting in greater productivity and confidence.<br><br>Imagine waking up every morning with a clear sense of purpose and drive, making decisions that align with your mission, and ultimately leading a fulfilling and purpose-driven life.<br></p><p>These are the key concepts we'll cover:</p><ol><li><strong>Missions Are Not Goals</strong>: Distinguish between a mission and a goal to harness the immense power of a well-defined purpose that drives you forward. Your mission shapes the big decisions and gives your life meaning, making it crucial to delineate from your goals.</li><li><strong>Mission Rules of Engagement</strong>: Dive into defining your mission with clarity by following the mission rules of engagement. Ensure your mission is congruent with your standards and boundaries, passionately aligned with your convictions and capable of withstanding the test of time.</li><li><strong>Transform Desires into a Byproduct of Your Mission</strong>: A mission should be transcendent and life-encompassing. When crafting your mission statement, aim to articulate a purpose that, when pursued, will organically manifest your desires, such as lifestyle choices, financial freedom, and personal growth, as a natural byproduct.</li></ol><h3></h3>", streamId: "ee4b42eed16d57b754039479e177f541", backdrop: "/backdrops/epic-mission.jpg" },
  { slug: "social-conversation-skills", title: "Compelling Conversation Masterclass", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/social-conversation-skills.png", duration: "25m 26s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 7, description: "Master The Social Skills That Captivate, Command Attention, and Exude Confidence", details: "<h5>From ignored and invisible to captivating gentleman who leaves a lasting impression</h5><p>Struggling with superficial or non-existent conversations? Sick of lacking impact in your interactions? Enhance your social and conversation skills for a commanding presence.</p><p>This masterclass is for you if you:</p><p>- Feel self-conscious in any conversation</p><p>- Find it difficult to maintain eye contact during a conversation, often looking away or down.</p><p>- Feel nervousness and discomfort when approaching social situations.</p><p>- Struggle to remember people's names, leading to embarrassment and potential loss of rapport.</p><p>- Avoid social gatherings or events due to anxiety about meeting new people.</p><p>Discover how to captivate and hold the attention of others, become more charming, and improve your confidence by mastering the art of compelling conversation and voice tonality.</p><p>Imagine effortlessly projecting power, authority, and confidence in every interaction, leading to deeper connections and a more commanding presence in your social and professional life.<br><br>We'll cover:</p><p>1. Mastering Voice Tonality: Learn to project a deep, compelling voice that commands attention and exudes confidence. Understand how the resonance from your chest can create a positive feedback loop, making you appear more comfortable and relaxed in your skin, ultimately projecting confidence to those around you.</p><p>2. Art of Compelling Conversation: Discover the essential keys to becoming an engaging conversationalist - active listening, maintaining eye contact, asking questions, and paraphrasing to show genuine understanding. Learn to create connections, share experiences, and make your company more enjoyable by being an authentic and relatable communicator.</p><p>3. Expert Storytelling: Uncover the power of storytelling in captivating and holding the attention of others. Explore the art of delivering a complete story arc, from setting up the context and introducing the motive to building intrigue, and ultimately, supplying resolution. Learn how to bridge word associations into engaging conversations and become a master storyteller to enhance your charm and charisma.</p>", streamId: "d57b0d2805dd8b5225c5bc38c3fd0fff", backdrop: "/backdrops/social-conversation-skills.jpg" },
  { slug: "frame-control", title: "Ultimate Influence And Impact", category: "Confidence", categorySlug: "confidence", instructorSlugs: ["lee-lambert"], thumbnail: "/thumbnails/frame-control.png", duration: "22m 22s", access: "premium", courseSlug: "midlife-confidence-unlocked", order: 3, description: "How To Own Every Interaction And Influence Others' Perceptions Of You", details: "<h5>Assert Your Influence: Mastering Different Frames for Ultimate Confidence and Success</h5><p>Whether you're dating, out with friends, gathering with family, or running a business, you can be more influential than you think.</p><p>Your frame is the perception of who you are to others and who they are to you. Your frames influence every interaction. The good news is, your frames are a choice and can be intentionally shaped to serve your best interests. </p><p>But that doesn't mean being fake or phony. You can align your frames with your personal belief systems and intentions. </p><p>Fed up with feeling powerless and misunderstood in relationships? Struggling to convey your true intentions and desires to others? Can’t figure out why your interactions keep going south?</p><p>Your previous attempts to navigate social dynamics have left you feeling deflated and overlooked. You’ve tried blending in, being agreeable, and downplaying your desires, but these strategies only seem to lead to more frustration. It’s time to shift your approach and reclaim your power when dealing with others.</p><p>Gain the insight and techniques to manage your frame to navigate various social dynamics. Say goodbye to feeling unheard, devalued, and unseen. Instead, learn how to be more assertive and express your intentions with confidence and clarity.</p><p>Discover the keys to understanding frame control and how to apply it any social situation. </p><h2></h2>", streamId: "11b65be75694d3414df737dccdadf95d", backdrop: "/backdrops/frame-control.jpg" },
  { slug: "instant-impressive-image", title: "Instant Impressive Image", category: "Image & Style", categorySlug: "image-style", instructorSlugs: ["gavin-parker"], thumbnail: "/thumbnails/instant-impressive-image.png", duration: "", access: "premium", courseSlug: "instant-impressive-image", order: 1, description: "Get noticed, even if you're average-looking, balding, short, with a dad bod", details: "<p>How you look is the easiest and fastest way to increase attraction. This includes style, wardrobe, and grooming. But image isn’t just about how you look, it’s also about how others perceive you, and what kind of impression you make. Just a few simple tweaks here and there, and you’ll be head-turning attractive in no time!</p>", streamId: "b4405ee828fcdf77774f91242a101ea4", backdrop: "/backdrops/instant-impressive-image.jpg" },
];

// ---- helpers ----------------------------------------------------------------

export const getInstructor = (slug: string): Instructor | undefined =>
  instructors.find((i) => i.slug === slug);

export const instructorNames = (slugs: string[]): string => {
  const names = slugs.map((s) => getInstructor(s)?.name).filter(Boolean) as string[];
  if (names.length <= 1) return names.join('');
  return `${names.slice(0, -1).join(', ')} & ${names[names.length - 1]}`;
};

export const getCourse = (slug: string | null): Course | undefined =>
  slug ? courses.find((c) => c.slug === slug) : undefined;

export const lessonsByCategory = (categoryName: string): Lesson[] =>
  lessons.filter((l) => l.category === categoryName);

export const categoryCount = (categoryName: string): number =>
  lessonsByCategory(categoryName).length;

export const freeLessons = (): Lesson[] => lessons.filter((l) => l.access === 'free');
export const premiumLessons = (): Lesson[] => lessons.filter((l) => l.access === 'premium');

export const lessonsByInstructor = (slug: string): Lesson[] =>
  lessons.filter((l) => l.instructorSlugs.includes(slug));

/** Other lessons in the same course, in course order. */
export const lessonsByCourse = (courseSlug: string): Lesson[] =>
  lessons
    .filter((l) => l.courseSlug === courseSlug)
    .sort((a, b) => (a.order ?? 0) - (b.order ?? 0));

export const getCategory = (slug: string): Category | undefined =>
  categories.find((c) => c.slug === slug);

export const relatedLessons = (lesson: Lesson, limit = 3): Lesson[] =>
  lessons
    .filter((l) => l.slug !== lesson.slug && l.category === lesson.category)
    .concat(lessons.filter((l) => l.slug !== lesson.slug && l.category !== lesson.category))
    .slice(0, limit);

export interface LessonCardProps {
  title: string;
  category: string;
  instructor: string;
  thumbnail: string;
  duration: string;
  access: 'free' | 'premium';
  href: string;
}
export const toCardProps = (l: Lesson): LessonCardProps => ({
  title: l.title,
  category: l.category,
  instructor: instructorNames(l.instructorSlugs),
  thumbnail: l.thumbnail,
  duration: l.duration,
  access: l.access,
  href: `/lessons/${l.slug}`,
});
